USE SmartBusDB;
GO
PRINT N'Import dữ liệu SmartBus V3: xe bus + du lịch';
GO
SET NOCOUNT ON;
GO

/* SmartBus v3.1 import preflight: widen text columns before MERGE/INSERT to avoid truncation errors */
IF OBJECT_ID('bus_routes','U') IS NOT NULL
BEGIN
    IF COL_LENGTH('bus_routes','fare') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN fare NVARCHAR(500) NULL;
    IF COL_LENGTH('bus_routes','operating_time') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN operating_time NVARCHAR(1000) NULL;
    IF COL_LENGTH('bus_routes','interval_text') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN interval_text NVARCHAR(500) NULL;
    IF COL_LENGTH('bus_routes','first_trip_time') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN first_trip_time NVARCHAR(200) NULL;
    IF COL_LENGTH('bus_routes','last_trip_time') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN last_trip_time NVARCHAR(200) NULL;
    IF COL_LENGTH('bus_routes','operation_days') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN operation_days NVARCHAR(500) NULL;
    IF COL_LENGTH('bus_routes','lunch_start_time') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN lunch_start_time NVARCHAR(500) NULL;
    IF COL_LENGTH('bus_routes','lunch_end_time') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN lunch_end_time NVARCHAR(500) NULL;
    IF COL_LENGTH('bus_routes','operating_hours') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN operating_hours NVARCHAR(1000) NULL;
    IF COL_LENGTH('bus_routes','frequency_text') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN frequency_text NVARCHAR(500) NULL;
    IF COL_LENGTH('bus_routes','speed_range_text') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN speed_range_text NVARCHAR(500) NULL;
    IF COL_LENGTH('bus_routes','break_time_text') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN break_time_text NVARCHAR(1000) NULL;
    IF COL_LENGTH('bus_routes','source_text') IS NOT NULL ALTER TABLE bus_routes ALTER COLUMN source_text NVARCHAR(2000) NULL;
END
GO
IF OBJECT_ID('bus_stops','U') IS NOT NULL
BEGIN
    IF COL_LENGTH('bus_stops','address') IS NOT NULL ALTER TABLE bus_stops ALTER COLUMN address NVARCHAR(500) NULL;
END
GO
IF OBJECT_ID('tourist_places','U') IS NOT NULL
BEGIN
    IF COL_LENGTH('tourist_places','address') IS NOT NULL ALTER TABLE tourist_places ALTER COLUMN address NVARCHAR(500) NULL;
    IF COL_LENGTH('tourist_places','opening_hours') IS NOT NULL ALTER TABLE tourist_places ALTER COLUMN opening_hours NVARCHAR(255) NULL;
    IF COL_LENGTH('tourist_places','image_source') IS NULL ALTER TABLE tourist_places ADD image_source NVARCHAR(1000) NULL;
    IF COL_LENGTH('tourist_places','note') IS NULL ALTER TABLE tourist_places ADD note NVARCHAR(MAX) NULL;
    IF COL_LENGTH('tourist_places','image_url') IS NOT NULL ALTER TABLE tourist_places ALTER COLUMN image_url NVARCHAR(1000) NULL;
    IF COL_LENGTH('tourist_places','image_url_2') IS NOT NULL ALTER TABLE tourist_places ALTER COLUMN image_url_2 NVARCHAR(1000) NULL;
    IF COL_LENGTH('tourist_places','image_url_3') IS NOT NULL ALTER TABLE tourist_places ALTER COLUMN image_url_3 NVARCHAR(1000) NULL;
    IF COL_LENGTH('tourist_places','source_url') IS NOT NULL ALTER TABLE tourist_places ALTER COLUMN source_url NVARCHAR(2000) NULL;
    IF COL_LENGTH('tourist_places','source_name') IS NOT NULL ALTER TABLE tourist_places ALTER COLUMN source_name NVARCHAR(500) NULL;
    IF COL_LENGTH('tourist_places','best_time') IS NOT NULL ALTER TABLE tourist_places ALTER COLUMN best_time NVARCHAR(500) NULL;
    IF COL_LENGTH('tourist_places','ticket_price_text') IS NOT NULL ALTER TABLE tourist_places ALTER COLUMN ticket_price_text NVARCHAR(500) NULL;
END
GO
MERGE provinces AS t USING (SELECT N'QT' AS code) AS s ON t.code=s.code WHEN MATCHED THEN UPDATE SET name=N'Quảng Trị', region=N'Bắc Trung Bộ', country=N'Việt Nam', note=N'Dữ liệu tuyến nội tỉnh theo QĐ 241/QĐ-UBND; điểm dừng nhỏ V2 có phần ước lượng GPS.', updated_at=SYSDATETIME() WHEN NOT MATCHED THEN INSERT(code,name,region,country,note) VALUES(N'QT',N'Quảng Trị',N'Bắc Trung Bộ',N'Việt Nam',N'Dữ liệu tuyến nội tỉnh theo QĐ 241/QĐ-UBND; điểm dừng nhỏ V2 có phần ước lượng GPS.');
MERGE provinces AS t USING (SELECT N'HUE' AS code) AS s ON t.code=s.code WHEN MATCHED THEN UPDATE SET name=N'Huế / Thành phố Huế', region=N'Bắc Trung Bộ', country=N'Việt Nam', note=N'Dữ liệu tuyến theo Bến xe Huế/Visit Hue; GPS điểm dừng nhỏ có phần ước lượng.', updated_at=SYSDATETIME() WHEN NOT MATCHED THEN INSERT(code,name,region,country,note) VALUES(N'HUE',N'Huế / Thành phố Huế',N'Bắc Trung Bộ',N'Việt Nam',N'Dữ liệu tuyến theo Bến xe Huế/Visit Hue; GPS điểm dừng nhỏ có phần ước lượng.');
MERGE provinces AS t USING (SELECT N'DN' AS code) AS s ON t.code=s.code WHEN MATCHED THEN UPDATE SET name=N'Đà Nẵng', region=N'Nam Trung Bộ', country=N'Việt Nam', note=N'Dữ liệu tuyến theo DanangBus/Moovit; GPS điểm dừng nhỏ có phần ước lượng.', updated_at=SYSDATETIME() WHEN NOT MATCHED THEN INSERT(code,name,region,country,note) VALUES(N'DN',N'Đà Nẵng',N'Nam Trung Bộ',N'Việt Nam',N'Dữ liệu tuyến theo DanangBus/Moovit; GPS điểm dừng nhỏ có phần ước lượng.');
MERGE provinces AS t USING (SELECT N'QNG' AS code) AS s ON t.code=s.code WHEN MATCHED THEN UPDATE SET name=N'Quảng Ngãi', region=N'Nam Trung Bộ', country=N'Việt Nam', note=N'Dữ liệu tuyến theo Sở Xây dựng Quảng Ngãi QĐ 396/QĐ-SXD 2025; GPS điểm dừng nhỏ có phần ước lượng.', updated_at=SYSDATETIME() WHEN NOT MATCHED THEN INSERT(code,name,region,country,note) VALUES(N'QNG',N'Quảng Ngãi',N'Nam Trung Bộ',N'Việt Nam',N'Dữ liệu tuyến theo Sở Xây dựng Quảng Ngãi QĐ 396/QĐ-SXD 2025; GPS điểm dừng nhỏ có phần ước lượng.');
GO
