DECLARE @placeId INT=(SELECT TOP 1 id FROM tourist_places WHERE external_place_code=N'QT_PLACE_THANH_CO_QUANG_TRI'); DECLARE @stopId INT=(SELECT TOP 1 id FROM bus_stops WHERE external_stop_code=N'QT_STOP_THI_XA_QUANG_TRI_THANH_CO'); DECLARE @routeCode NVARCHAR(50)=(SELECT TOP 1 route_code FROM bus_routes WHERE province_code=N'QT' AND route_number=N'02'); IF @placeId IS NOT NULL AND @stopId IS NOT NULL BEGIN UPDATE tourist_places SET nearest_stop_id=@stopId WHERE id=@placeId; MERGE place_nearby_stops AS t USING (SELECT @placeId AS place_id, @stopId AS stop_id, COALESCE(@routeCode,N'02') AS route_code) AS src ON t.place_id=src.place_id AND t.stop_id=src.stop_id AND t.route_code=src.route_code WHEN MATCHED THEN UPDATE SET distance_meters=0, walking_minutes=0, note=N'Liên kết bus dùng khoảng cách Haversine tới điểm dừng trong dữ liệu V2; khoảng cách đi bộ thực tế cần kiểm tra bản đồ.' WHEN NOT MATCHED THEN INSERT(place_id,stop_id,route_code,distance_meters,walking_minutes,note) VALUES(@placeId,@stopId,COALESCE(@routeCode,N'02'),0,0,N'Liên kết bus dùng khoảng cách Haversine tới điểm dừng trong dữ liệu V2; khoảng cách đi bộ thực tế cần kiểm tra bản đồ.'); END
GO
